// PATTERN BANK: Progressive Groove
// Sasha and Digweed hypnotic minimal groove
setcps(132/60/4)
let progFilter = slider(1500, 200, 5000, 10, "PROG Filter")
let groove = slider(0.6, 0, 1, 0.01, "GROOVE Depth")

let kick = s("bd").bank("RolandTR909").gain(0.9).struct("x x x x")
let rim = s("sd").bank("RolandTR909").gain(0.25).struct("~ [~ x] ~ ~").speed(1.5)
let hats = s("hh").bank("RolandTR909").gain(0.35).struct("x [x x] x [x x]").cutoff(4000)

let bassline = note("<c2 c2 c2 eb2 c2 c2 g1 ab1>")
  .s("sawtooth")
  .cutoff(perlin.range(200, progFilter).slow(8))
  .resonance(12)
  .decay(0.2)
  .sustain(0.05)
  .gain(groove.mul(0.7))
  .struct("x ~ x [~ x] x ~ x ~")

let deepPad = note("<[c3,g3] [eb3,bb3] [ab2,eb3] [bb2,f3]>".slow(4))
  .s("gm_pad_sweep")
  .gain(groove.mul(0.3))
  .cutoff(perlin.range(400, 2000).slow(16))
  .room(0.8)
  .size(0.85)

stack(kick, rim, hats, bassline, deepPad)
